#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int **B = (int**)malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        B[i] = (int*)malloc(N * sizeof(int));
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            scanf("%d", &B[i][j]);
        }
    }
    int *A = (int*)malloc(N * sizeof(int));
    A[0] = 0;
    for (int i = 1; i < N; i++) {
        A[i] = -B[0][i];
    }
    for (int i = 0; i < Q; i++) {
        int p;
        scanf("%d", &p);
        p--;
        for (int j = 0; j < N; j++) {
            scanf("%d", &B[p][j]);
            B[j][p] = B[p][j];
        }
        for (int j = 0; j < N; j++) {
            if (j == 0) {
                A[j] = 0;
            } else {
                A[j] = -B[0][j];
            }
        }
        for (int j = 0; j < N; j++) {
            printf("%d ", A[j]);
        }
        printf("\n");
    }
    free(A);
    for (int i = 0; i < N; i++) {
        free(B[i]);
    }
    free(B);
    return 0;
}

