import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int Q = scanner.nextInt();
        int[][] B = new int[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                B[i][j] = scanner.nextInt();
            }
        }
        int[] A = new int[N];
        A[0] = 0;
        for (int i = 1; i < N; i++) {
            A[i] = -B[0][i];
        }
        for (int i = 0; i < Q; i++) {
            int p = scanner.nextInt();
            p--;
            for (int j = 0; j < N; j++) {
                B[p][j] = scanner.nextInt();
                B[j][p] = B[p][j];
            }
            for (int j = 0; j < N; j++) {
                if (j == 0) {
                    A[j] = 0;
                } else {
                    A[j] = -B[0][j];
                }
            }
            for (int j = 0; j < N; j++) {
                System.out.print(A[j] + " ");
            }
            System.out.println();
        }
