    const p = parseInt(readline()) - 1;
    const F = readline().split(' ').map(x => parseInt(x));
    for (let j = 0; j < N; j++) {
        B[p][j] = F[j];
        B[j][p] = F[j];
    }
    for (let j = 0; j < N; j++) {
        if (j == 0) {
            A[j] = 0;
